// This script should be placed in a new n8n "Code" node
// following the "Parsed Content (Financials)" node.

for (const item of $input.all()) {
  const {
    financial_year: financialYear,
    original_code: originalCode,
  } = item.json;

  if (!financialYear || !originalCode) {
    throw new Error("Input is missing required financial_year or original_code fields.");
  }

  // 1. Extract the base year from the financial_year string (e.g., "2023-24" -> "2023")
  const yearMatch = financialYear.match(/^\d{4}/);

  if (!yearMatch) {
    throw new Error(`Could not parse a valid year from financial_year: "${financialYear}"`);
  }
  const year = yearMatch[0];

  // 2. Define the target date for the historical exchange rate (Dec 31st of the reporting year)
  const targetDate = `${year}-12-31`;

  // 3. Check if the original currency is already USD to determine if an API call is needed.
  const originalCodeUpperCased = originalCode.toUpperCase();

  item.json = {
    target_date: targetDate,
    original_code: originalCodeUpperCased,
    skip_api_call: originalCodeUpperCased === 'USD',
  }
}

return $input.all();

// This script should be placed in a new n8n "Code" node
// following the "Get Exchange Rate" HTTP Request node.

for (const item of $input.all()) {
  // The original financial data is nested from a previous step.
  const { original_code: originalCode } = $('Start').first().json;

  // The API response from the HTTP Request node is at the top level of the item's JSON.
  const { date, rates, target_date: targetDate, skip_api_call: skipApiCall } = item.json;

  if (skipApiCall) {
    item.json = {
      original_code: originalCode,
      usd_exchange_rate: 1.0,
      rate_date: targetDate,
    }
  } else {
    if (!rates || typeof rates.USD === 'undefined' || !date) {
      throw new Error("API response from Frankfurter is missing 'rates.USD' or 'date'.");
    }
    item.json = {
      original_code: originalCode,
      usd_exchange_rate: rates.USD,
      rate_date: date,
    };
  }
}

// Return the modified items, which now contain the complete currency object.
// The structure is ready for the "Schema Validation (Financials)" node.
return $input.all();
